export interface Project {
  id: string;
  title: string;
  category: string;
  description: string;
  imageUrl: string;
  overviewImageUrl?: string; // Secondary showcase image for the overview section
  year?: string;
  role?: string;
  tools?: string[];
  challenge?: string;
  solution?: string;
  quote?: string; // Added for the specific objective quote
  // Detailed Case Study Fields
  problemStatement?: string;
  researchInsights?: string;
  impactMetric?: string;
  impactLabel?: string;
  reflection?: string;
}

export interface ChatMessage {
  role: 'user' | 'assistant';
  content: string;
}

export type View = 'work' | 'case-studies' | 'info' | 'project-detail';

export enum Section {
  HERO = 'hero',
  WORK = 'work',
  PROJECTS = 'projects',
  CONTACT = 'contact'
}

import React, { useEffect, useState, useCallback, useRef } from 'react';
import Header from './components/Header';
import ProjectCard from './components/ProjectCard';
import GlassButton from './components/GlassButton';
import CustomCursor from './components/CustomCursor';
import LoadingScreen from './components/LoadingScreen';
import AIStrategist from './components/AIStrategist';
import { PROJECTS as DEFAULT_PROJECTS, SIDE_PROJECTS } from './constants';
import { View, Project } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('work');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isEditMode, setIsEditMode] = useState(false);
  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('ux_portfolio_projects');
    return saved ? JSON.parse(saved) : DEFAULT_PROJECTS;
  });

  useEffect(() => {
    localStorage.setItem('ux_portfolio_projects', JSON.stringify(projects));
  }, [projects]);

  useEffect(() => {
    const handleScroll = () => {
      const layers = document.querySelectorAll('.parallax-layer');
      layers.forEach((layer) => {
        const element = layer as HTMLElement;
        const rect = element.getBoundingClientRect();
        const viewportHeight = window.innerHeight;

        if (rect.top < viewportHeight && rect.bottom > 0) {
          const speed = 0.08; 
          const yPos = (rect.top - viewportHeight / 2) * speed;
          element.style.transform = `translateY(${yPos}px)`;
        }
      });
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const revealOptions = {
      threshold: 0.1,
      rootMargin: '0px 0px -50px 0px'
    };

    const revealObserver = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const target = entry.target as HTMLElement;
          const delay = target.dataset.delay || '0';

          setTimeout(() => {
            target.classList.add('reveal-visible');
          }, parseInt(delay));

          revealObserver.unobserve(target);
        }
      });
    }, revealOptions);

    const revealObserverRef = revealObserver;
    const revealElements = document.querySelectorAll('.reveal');
    revealElements.forEach(el => revealObserverRef.observe(el));

    if (!isLoading) {
      window.scrollTo(0, 0);
    }

    return () => revealObserverRef.disconnect();
  }, [currentView, isLoading, selectedProject]);

  const updateProjectField = (id: string, field: keyof Project, value: string) => {
    setProjects(prev => prev.map(p => p.id === id ? { ...p, [field]: value } : p));
  };

  const handleProjectClick = (project: Project) => {
    setSelectedProject(project);
    setCurrentView('project-detail');
  };

  const renderView = () => {
    const activeProject = selectedProject ? projects.find(p => p.id === selectedProject.id) : null;

    switch (currentView) {
      case 'case-studies':
        return <CaseStudiesView projects={projects} />;
      case 'info':
        return <InfoView />;
      case 'project-detail':
        return activeProject ? (
          <ProjectDetailView 
            project={activeProject} 
            isEditMode={isEditMode}
            onUpdateField={(field, val) => updateProjectField(activeProject.id, field, val)}
            onBack={() => setCurrentView('work')} 
            onNext={() => {
              const idx = projects.findIndex(p => p.id === activeProject.id);
              const next = projects[(idx + 1) % projects.length];
              setSelectedProject(next);
              window.scrollTo({ top: 0, behavior: 'smooth' });
            }}
          />
        ) : <WorkView projects={projects} onProjectClick={handleProjectClick} />;
      default:
        return <WorkView projects={projects} onProjectClick={handleProjectClick} />;
    }
  };

  return (
    <div className="min-h-screen selection:bg-white selection:text-black bg-black custom-cursor-area">
      <CustomCursor />

      {isLoading && <LoadingScreen onLoadingComplete={() => setIsLoading(false)} />}

      <Header currentView={currentView} onViewChange={(view) => {
        setCurrentView(view);
        setSelectedProject(null);
      }} />

      <main className={`transition-opacity duration-1000 ${isLoading ? 'opacity-0 blur-xl' : 'opacity-100'}`}>
        {renderView()}
      </main>

      {/* Persistence Toggle / Design Mode */}
      <div className="fixed bottom-8 left-8 z-[200]">
        <button 
          onClick={() => setIsEditMode(!isEditMode)}
          className={`px-4 py-2 rounded-full text-[10px] font-black tracking-widest uppercase transition-all border ${
            isEditMode ? 'bg-orange-500 border-orange-400 text-white' : 'glass border-white/10 text-white/40 hover:text-white'
          }`}
        >
          {isEditMode ? 'Design Mode: ON' : 'Design Mode: OFF'}
        </button>
      </div>

      <footer id="contact" className={`py-32 px-6 border-t border-white/5 bg-black/50 backdrop-blur-md transition-opacity duration-1000 ${isLoading ? 'opacity-0' : 'opacity-100'}`}>
        <div className="max-w-7xl auto flex flex-col items-center text-center reveal">
          <h2 className="text-5xl md:text-8xl font-bold tracking-tighter mb-20">
            Let's <span className="text-white/40 italic">build</span> together.
          </h2>

          <div className="w-full pt-12 border-t border-white/5 flex flex-col md:flex-row justify-between items-center gap-8 text-white/30 text-xs font-bold tracking-widest uppercase">
            <div>© 2024 JT DESIGN STUDIO</div>
            <div className="flex gap-8">
              <a href="#" className="hover:text-white transition-colors">LinkedIn</a>
              <a href="#" className="hover:text-white transition-colors">Behance</a>
              <a href="#" className="hover:text-white transition-colors">Instagram</a>
            </div>
            <div>LOCATED IN BERLIN, DE</div>
          </div>
        </div>
      </footer>
    </div>
  );
};

const WorkView: React.FC<{ projects: Project[]; onProjectClick: (project: Project) => void }> = ({ projects, onProjectClick }) => (
  <>
    <section id="hero" className="min-h-screen flex flex-col justify-start items-center px-6 relative overflow-hidden pt-32 lg:pt-48">
      <div className="absolute top-1/4 left-1/4 w-[500px] h-[500px] bg-blue-500/5 rounded-full blur-[120px] -z-10 animate-pulse"></div>
      <div className="absolute bottom-1/4 right-1/4 w-[600px] h-[600px] bg-orange-500/5 rounded-full blur-[150px] -z-10 animate-pulse [animation-delay:2s]"></div>

      <div className="max-w-7xl mx-auto w-full grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-24 items-center">
        <div className="reveal order-2 lg:order-1 text-left" data-delay="100">
          <div className="inline-block glass px-4 py-1.5 rounded-full text-[10px] font-bold tracking-[0.3em] text-white/60 mb-8 border border-white/5 uppercase">
            PROJECT BUILDER
          </div>
          <h1 className="text-5xl md:text-7xl lg:text-8xl font-bold tracking-tighter leading-[0.9] mb-8">
            Designing <span className="text-white/40 italic">human</span> experiences.
          </h1>
          <p className="text-lg md:text-xl text-white/50 max-w-xl leading-relaxed">
            I craft minimalist digital products that solve complex user problems through empathy, data, and strategic product thinking.
          </p>
          <div className="mt-12 flex items-center gap-8">
            <div className="flex flex-col">
              <span className="text-[10px] font-bold text-white/20 tracking-widest uppercase mb-1">Previously</span>
              <span className="text-sm font-medium text-white/60">Integrate, Aquent</span>
            </div>
            <div className="w-[1px] h-10 bg-white/10"></div>
            <div className="flex flex-col">
              <span className="text-[10px] font-bold text-white/20 tracking-widest uppercase mb-1">Focus</span>
              <span className="text-sm font-medium text-white/60">Product</span>
            </div>
          </div>
        </div>

        <div className="reveal order-1 lg:order-2 relative flex justify-center items-center" data-delay="300">
          <div className="relative group p-1 glass rounded-[3rem] border border-white/5 overflow-hidden transition-all duration-700 hover:border-white/20 shadow-2xl">
            <div className="aspect-square w-full min-w-[300px] max-w-[450px] md:max-w-[500px] rounded-[2.5rem] overflow-hidden bg-black flex items-center justify-center">
              <img 
                src="https://cdn.midjourney.com/115b35c3-7cb2-46db-b226-6058e28a39cb/0_3.png" 
                alt="JT - decorative image" 
                className="w-full h-full object-cover scale-[1.05] group-hover:scale-110 transition-transform duration-1000 ease-out"
              />
            </div>
            <div className="absolute inset-0 pointer-events-none rounded-[3rem] border border-white/10 group-hover:border-white/20 transition-colors duration-500"></div>
          </div>
        </div>
      </div>
    </section>

    <section id="work" className="py-32 px-6 dot-grid">
      <div className="max-w-7xl mx-auto">
        <div className="flex flex-col md:flex-row justify-between items-end gap-6 mb-20 reveal">
          <div>
            <span className="text-xs font-bold tracking-[0.2em] text-white/30 uppercase mb-4 block">Selection</span>
            <h2 className="text-4xl md:text-6xl font-bold tracking-tight">Featured</h2>
          </div>
        </div>

        <div className="flex flex-col gap-12 md:gap-20">
          {projects.map((project, idx) => (
            <div key={project.id} className="reveal" data-delay={idx * 200}>
              <ProjectCard project={project} onClick={onProjectClick} />
            </div>
          ))}
        </div>
      </div>
    </section>

    <AIStrategist />

    <section id="personal-archive" className="py-32 px-6 bg-black dot-grid">
      <div className="max-w-6xl mx-auto">
        <div className="mb-24 text-center flex flex-col items-center gap-4 reveal">
          <h2 className="text-sm font-bold tracking-[0.6em] uppercase text-white">Personal</h2>
          <div className="w-12 h-[1px] bg-white/20 mt-1"></div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-12 gap-x-8 gap-y-16">
          {SIDE_PROJECTS.map((project, index) => {
            let colSpan = 'md:col-span-6';
            if (index === 0) colSpan = 'md:col-span-8';
            else if (index === 1) colSpan = 'md:col-span-4';
            else if (index === 2) colSpan = 'md:col-span-4';
            else if (index === 3) colSpan = 'md:col-span-8';

            return (
              <div 
                key={project.id} 
                data-cursor="project"
                data-delay={index * 100}
                className={`group flex flex-col ${colSpan} cursor-pointer reveal`}
              >
                <div className="relative rounded-2xl h-[240px] md:h-[340px] bg-[#0c0c0c] overflow-hidden border border-white/5 transition-all duration-700 group-hover:border-white/20 group-hover:scale-[1.02] shadow-lg">
                  <div className="parallax-layer w-full h-full will-change-transform">
                    <img 
                      src={project.imageUrl} 
                      alt={project.title} 
                      className="w-full h-full object-cover opacity-70 group-hover:opacity-100 scale-[1.05] group-hover:scale-[1.12] transition-transform duration-1000 ease-out"
                    />
                  </div>
                </div>
                <div className="mt-6">
                  <h3 className="text-xl font-bold text-white/90 group-hover:text-white transition-colors">
                    {project.title}
                  </h3>
                  <p className="text-white/40 text-sm mt-2">{project.category}</p>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </section>
  </>
);

const ProjectDetailView: React.FC<{ 
  project: Project; 
  isEditMode: boolean;
  onUpdateField: (field: keyof Project, val: string) => void;
  onBack: () => void; 
  onNext: () => void 
}> = ({ project, isEditMode, onUpdateField, onBack, onNext }) => {
  const [activeSection, setActiveSection] = useState('hero');

  const sections = [
    { id: 'hero', label: 'Intro' },
    { id: 'overview', label: 'Overview' },
    { id: 'problem', label: 'Problem' },
    { id: 'research', label: 'Research' },
    { id: 'solution', label: 'Solution' },
    { id: 'process', label: 'Process' },
    { id: 'design', label: 'Design' },
    { id: 'impact', label: 'Impact' },
    { id: 'reflection', label: 'Reflection' }
  ];

  useEffect(() => {
    const handleScroll = () => {
      const buffer = 150;
      let currentSectionId = sections[0].id;

      for (const section of sections) {
        const element = document.getElementById(section.id);
        if (element) {
          const rect = element.getBoundingClientRect();
          if (rect.top <= buffer) {
            currentSectionId = section.id;
          }
        }
      }

      setActiveSection(currentSectionId);
    };

    window.addEventListener("scroll", handleScroll, { passive: true });
    handleScroll();

    return () => window.removeEventListener("scroll", handleScroll);
  }, [sections]);

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({
        behavior: 'smooth',
        block: 'start'
      });
    }
  };

  const showNav = ['problem', 'research', 'solution', 'process', 'design', 'impact', 'reflection'].includes(activeSection) || 
                  (activeSection === 'overview' && window.scrollY > 400);

  const handleBlur = (field: keyof Project, e: React.FocusEvent<HTMLElement>) => {
    if (!isEditMode) return;
    onUpdateField(field, e.currentTarget.innerText);
  };

  return (
    <div className="bg-black min-h-screen relative selection:bg-orange-500 selection:text-white">

      <div 
        className={`fixed right-0 top-0 bottom-0 w-12 md:w-16 z-[100] hidden lg:flex flex-col items-center justify-center transition-all duration-700 ease-in-out ${
          showNav ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-12 pointer-events-none'
        }`}
      >
        <nav className="relative flex flex-col gap-6 items-center w-full">
          {sections.map((section) => {
            const isActive = activeSection === section.id;
            return (
              <button
                key={section.id}
                onClick={() => scrollToSection(section.id)}
                className="group relative flex items-center justify-center w-full h-8"
              >
                <div className={`absolute right-10 px-3 py-1.5 glass rounded-full border border-white/5 transition-all duration-500 pointer-events-none ${
                  isActive 
                    ? 'opacity-100 translate-x-0' 
                    : 'opacity-0 translate-x-2 group-hover:opacity-100 group-hover:translate-x-0'
                }`}>
                  <span className={`text-[9px] font-black tracking-[0.2em] uppercase whitespace-nowrap transition-colors duration-500 ${
                    isActive ? 'text-orange-500' : 'text-white'
                  }`}>
                    {section.label}
                  </span>
                </div>

                <div 
                  className={`w-1.5 h-1.5 rounded-full border transition-all duration-500 z-10 ${
                    isActive 
                      ? 'bg-orange-500 border-orange-500 scale-125 shadow-[0_0_12px_rgba(249,115,22,0.6)]' 
                      : 'bg-transparent border-white/20 group-hover:border-white/60 group-hover:scale-110'
                  }`}
                />
              </button>
            );
          })}
        </nav>

        <button 
          onClick={onBack}
          className="absolute bottom-8 group flex flex-col items-center gap-2 text-white/20 hover:text-white transition-colors"
        >
          <div className="w-8 h-8 rounded-full glass border border-white/10 flex items-center justify-center group-hover:border-orange-500 group-hover:text-orange-500 transition-all">
             <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
             </svg>
          </div>
          <span className="text-[7px] font-bold tracking-widest uppercase opacity-0 group-hover:opacity-100 transition-opacity">Exit</span>
        </button>
      </div>

      <section 
        id="hero"
        className="relative h-screen w-full overflow-hidden flex flex-col justify-end items-center px-6 pb-20 md:pb-32 lg:pr-24"
      >
        <div className="absolute inset-0 z-0">
          <img 
            src={project.imageUrl} 
            alt={project.title} 
            className="w-full h-full object-cover"
          />
          <div className="absolute inset-0 bg-gradient-to-t from-black via-black/40 to-transparent"></div>
        </div>

        <div className="relative z-10 w-full max-w-7xl mx-auto text-left">
          <div className="reveal" data-delay="100">
             <button 
                onClick={onBack}
                className="mb-12 glass px-6 py-2 rounded-full text-[10px] font-black tracking-[0.3em] uppercase flex items-center gap-3 hover:bg-white/10 transition-all group"
              >
                <svg className="w-4 h-4 transition-transform group-hover:-translate-x-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                </svg>
                EXIT PROJECT
              </button>

              <div className="flex flex-col md:flex-row md:items-end justify-between gap-8">
                <div>
                  <span className="text-[10px] font-black tracking-[0.6em] uppercase text-white/40 mb-4 block">Featured Case Study / {project.year}</span>
                  <h1 
                    contentEditable={isEditMode}
                    onBlur={(e) => handleBlur('title', e)}
                    className={`text-6xl md:text-[10vw] font-bold tracking-tighter leading-[0.8] mb-0 outline-none ${isEditMode ? 'hover:bg-white/5 cursor-text focus:bg-white/10' : ''}`}
                  >
                    {project.title.split(' ').map((word, i) => (
                      <span key={i} className={i % 2 === 1 ? 'text-white/20' : ''}>{word} </span>
                    ))}
                  </h1>
                </div>
                <div className="max-w-xs text-right hidden md:block">
                   <div className="text-[10px] font-black tracking-[0.3em] uppercase text-white/20 mb-4">Focus Area</div>
                   <div className="text-sm font-medium">{project.category.split(' • ')[1] || 'Product Design'}</div>
                </div>
              </div>
          </div>
        </div>

        <div className="absolute bottom-2 left-1/2 -translate-x-1/2 flex flex-col items-center gap-4 animate-bounce opacity-40">
           <span className="text-[8px] font-bold tracking-widest uppercase">Explore Story</span>
           <div className="w-[1px] h-12 bg-white/20"></div>
        </div>
      </section>

      <section className="relative z-20 bg-black pt-32 lg:pr-24">
        <div className="max-w-7xl mx-auto px-6">
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-16 lg:gap-24">

            <div className="lg:col-span-8 space-y-48 md:space-y-64">
              <div id="overview" className="scroll-mt-32 reveal" data-delay="200">
                <div className="text-[10px] font-black tracking-[0.5em] uppercase text-white/20 mb-12">01 / Overview</div>
                <h2 className="text-3xl md:text-6xl font-bold tracking-tight mb-12 leading-tight">
                  Driving excellence through <span className="text-white/40 italic">minimalist architecture.</span>
                </h2>
                <p 
                  contentEditable={isEditMode}
                  onBlur={(e) => handleBlur('description', e)}
                  className={`text-xl md:text-3xl text-white/60 leading-relaxed font-light mb-16 italic border-l-2 border-white/10 pl-10 outline-none ${isEditMode ? 'hover:bg-white/5 cursor-text' : ''}`}
                >
                  "{project.description}"
                </p>
                <p className="text-lg md:text-xl text-white/50 leading-relaxed font-light max-w-2xl">
                  The goal was not just to redesign a surface-level interface, but to re-engineer the entire information architecture to serve user needs first.
                </p>
              </div>
            </div>

            <div className="lg:col-span-4 space-y-12 h-fit pb-24 lg:pr-12">
              <div id="details-box" className="glass bg-zinc-900/90 p-12 rounded-[3.5rem] border border-white/20 backdrop-blur-3xl reveal shadow-2xl" data-delay="500">
                <div className="space-y-16">
                  <div>
                    <span className="text-[10px] font-black tracking-[0.4em] uppercase text-white/50 block mb-6">Engagement Role</span>
                    <p className="text-3xl font-bold tracking-tight text-white">{project.role}</p>
                  </div>
                  <div>
                    <span className="text-[10px] font-black tracking-[0.4em] uppercase text-white/50 block mb-6">Tools Used</span>
                    <div className="flex flex-wrap gap-2 mt-4">
                      {project.tools?.map(tool => (
                        <span key={tool} className="text-[10px] font-bold px-4 py-2 bg-white/10 rounded-full border border-white/15 text-white/90">{tool}</span>
                      ))}
                    </div>
                  </div>
                  <div className="pt-12 border-t border-white/10">
                    <GlassButton className="w-full py-6 text-[10px] font-black tracking-[0.4em] uppercase group/cta hover:bg-orange-500 transition-all">
                      Visit Project
                    </GlassButton>
                  </div>
                </div>
              </div>
            </div>
          </div>

          {project.overviewImageUrl && (
            <div className="w-full my-12 md:my-16 reveal group/over" data-delay="300">
              <div className="relative glass p-2 md:p-4 rounded-[3rem] md:rounded-[5rem] overflow-hidden shadow-[0_0_150px_rgba(255,255,255,0.03)] border border-white/10 transition-all duration-1000 ring-1 ring-white/10">
                <img 
                  src={project.overviewImageUrl} 
                  alt="Overview Details" 
                  className="w-full h-[70vh] md:h-[90vh] lg:h-[105vh] object-cover rounded-[2.5rem] md:rounded-[4.5rem] opacity-95 group-hover/over:opacity-100 group-hover/over:scale-[1.03] transition-all duration-[3s] ease-out"
                />
                <div className="absolute inset-0 rounded-[3rem] md:rounded-[5rem] border border-white/5 pointer-events-none"></div>
              </div>
            </div>
          )}

          <div className="grid grid-cols-1 lg:grid-cols-12 gap-16 lg:gap-24 pt-12 md:pt-16">
            <div className="lg:col-span-8 space-y-48 md:space-y-64 pb-48">

              {/* UPDATED PROBLEM SECTION TO MATCH SCREENSHOT */}
              <div id="problem" className="scroll-mt-32 reveal" data-delay="300">
                <div className="text-[10px] font-black tracking-[0.5em] uppercase text-white/20 mb-12">02 / THE PROBLEM</div>
                <h2 className="text-4xl md:text-7xl font-bold tracking-tight mb-16 leading-tight">
                  Defining the <span className="text-white/40 italic font-medium">friction.</span>
                </h2>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
                  <div className="space-y-8">
                    <p 
                      contentEditable={isEditMode}
                      onBlur={(e) => handleBlur('problemStatement', e)}
                      className={`text-lg md:text-xl text-white/60 leading-relaxed outline-none ${isEditMode ? 'hover:bg-white/5 cursor-text' : ''}`}
                    >
                      {project.problemStatement || "We identified a significant gap between technical complexity and user intuition, resulting in drop-offs at critical conversion points."}
                    </p>
                  </div>

                  <div className="bg-[#0c0c0c] p-10 rounded-[2.5rem] border border-white/5 relative overflow-hidden group">
                    <div className="absolute inset-0 bg-blue-500/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
                    {/* Blue border box matching screenshot */}
                    <div className="relative border-2 border-blue-500/60 p-8 md:p-12">
                      <span className="text-[10px] font-black tracking-[0.3em] uppercase text-[#ff6b00] mb-6 block">CORE OBJECTIVE</span>
                      <p 
