          <div className="inline-block glass px-4 py-1.5 rounded-full text-[10px] font-bold tracking-[0.3em] text-white/60 mb-8 border border-white/5 uppercase">
            PROJECT BUILDER
          </div>
          <h1 className="text-5xl md:text-7xl lg:text-8xl font-bold tracking-tighter leading-[0.9] mb-8">
