  onBack: () => void; 
  onNext: () => void 
}> = ({ project, projects, isEditMode, onUpdateField, onBack, onNext }) => {
  const [activeSection, setActiveSection] = useState('hero');

  const sections = [
    { id: 'hero', label: 'Intro' },
    { id: 'overview', label: 'Overview' },
    { id: 'problem', label: 'Problem' },
    { id: 'research', label: 'Research' },
    { id: 'solution', label: 'Solution' },
    { id: 'process', label: 'Process' },
    { id: 'design', label: 'Design' },
    { id: 'impact', label: 'Impact' },
    { id: 'reflection', label: 'Reflection' }
  ];

  useEffect(() => {
    const handleScroll = () => {
      const buffer = 150;
      let currentSectionId = sections[0].id;

      for (const section of sections) {
        const element = document.getElementById(section.id);
        if (element) {
          const rect = element.getBoundingClientRect();
          if (rect.top <= buffer) {
            currentSectionId = section.id;
          }
        }
      }

      setActiveSection(currentSectionId);
    };

    window.addEventListener("scroll", handleScroll, { passive: true });
    handleScroll();

    return () => window.removeEventListener("scroll", handleScroll);
  }, [sections]);

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id);
    if (element) {
      element.scrollIntoView({
        behavior: 'smooth',
        block: 'start'
      });
    }
  };

  const showNav = ['problem', 'research', 'solution', 'process', 'design', 'impact', 'reflection'].includes(activeSection) || 
                  (activeSection === 'overview' && window.scrollY > 400);

  const handleBlur = (field: keyof Project, e: React.FocusEvent<HTMLElement>) => {
    if (!isEditMode) return;
    onUpdateField(field, e.currentTarget.innerText);
  };

