import React, { useEffect, useState, useCallback, useRef } from 'react';
import Header from './components/Header';
import ProjectCard from './components/ProjectCard';
import GlassButton from './components/GlassButton';
import CustomCursor from './components/CustomCursor';
import LoadingScreen from './components/LoadingScreen';
import AIStrategist from './components/AIStrategist';
import { PROJECTS as DEFAULT_PROJECTS, SIDE_PROJECTS } from './constants';
import { View, Project } from './types';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('work');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isEditMode, setIsEditMode] = useState(false);
  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('ux_portfolio_projects');
    return saved ? JSON.parse(saved) : DEFAULT_PROJECTS;
  });

  useEffect(() => {
    localStorage.setItem('ux_portfolio_projects', JSON.stringify(projects));
  }, [projects]);

  useEffect(() => {
    const handleScroll = () => {
      const layers = document.querySelectorAll('.parallax-layer');
      layers.forEach((layer) => {
        const element = layer as HTMLElement;
        const rect = element.getBoundingClientRect();
        const viewportHeight = window.innerHeight;

        if (rect.top < viewportHeight && rect.bottom > 0) {
          const speed = 0.08; 
          const yPos = (rect.top - viewportHeight / 2) * speed;
          element.style.transform = `translateY(${yPos}px)`;
        }
      });
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const revealOptions = {
      threshold: 0.1,
      rootMargin: '0px 0px -50px 0px'
    };

    const revealObserver = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const target = entry.target as HTMLElement;
          const delay = target.dataset.delay || '0';

          setTimeout(() => {
            target.classList.add('reveal-visible');
          }, parseInt(delay));

          revealObserver.unobserve(target);
        }
      });
    }, revealOptions);

    const revealObserverRef = revealObserver;
    const revealElements = document.querySelectorAll('.reveal');
    revealElements.forEach(el => revealObserverRef.observe(el));

    if (!isLoading) {
      window.scrollTo(0, 0);
    }

    return () => revealObserverRef.disconnect();
  }, [currentView, isLoading, selectedProject]);

  const updateProjectField = (id: string, field: keyof Project, value: string) => {
    setProjects(prev => prev.map(p => p.id === id ? { ...p, [field]: value } : p));
  };

  const handleProjectClick = (project: Project) => {
    setSelectedProject(project);
    setCurrentView('project-detail');
  };

  const renderView = () => {
    const activeProject = selectedProject ? projects.find(p => p.id === selectedProject.id) : null;

    switch (currentView) {
      case 'case-studies':
        return <CaseStudiesView projects={projects} />;
      case 'info':
        return <InfoView />;
      case 'project-detail':
        return activeProject ? (
          <ProjectDetailView 
            project={activeProject} 
            projects={projects}
            isEditMode={isEditMode}
            onUpdateField={(field, val) => updateProjectField(activeProject.id, field, val)}
            onBack={() => setCurrentView('work')} 
            onNext={() => {
              const idx = projects.findIndex(p => p.id === activeProject.id);
              const next = projects[(idx + 1) % projects.length];
              setSelectedProject(next);
              window.scrollTo({ top: 0, behavior: 'smooth' });
            }}
          />
        ) : <WorkView projects={projects} onProjectClick={handleProjectClick} />;
      default:
        return <WorkView projects={projects} onProjectClick={handleProjectClick} />;
    }
  };

  return (
    <div className="min-h-screen selection:bg-white selection:text-black bg-black custom-cursor-area">
      <CustomCursor />

      {isLoading && <LoadingScreen onLoadingComplete={() => setIsLoading(false)} />}

      <Header currentView={currentView} onViewChange={(view) => {
        setCurrentView(view);
        setSelectedProject(null);
      }} />

      <main className={`transition-opacity duration-1000 ${isLoading ? 'opacity-0 blur-xl' : 'opacity-100'}`}>
        {renderView()}
      </main>

      {/* Persistence Toggle / Design Mode */}
      <div className="fixed bottom-8 left-8 z-[200]">
        <button 
          onClick={() => setIsEditMode(!isEditMode)}
          className={`px-4 py-2 rounded-full text-[10px] font-black tracking-widest uppercase transition-all border ${
            isEditMode ? 'bg-orange-500 border-orange-400 text-white' : 'glass border-white/10 text-white/40 hover:text-white'
          }`}
        >
          {isEditMode ? 'Design Mode: ON' : 'Design Mode: OFF'}
        </button>
      </div>

      <footer id="contact" className={`py-32 px-6 border-t border-white/5 bg-black/50 backdrop-blur-md transition-opacity duration-1000 ${isLoading ? 'opacity-0' : 'opacity-100'}`}>
        <div className="max-w-7xl auto flex flex-col items-center text-center reveal">
          <h2 className="text-5xl md:text-8xl font-bold tracking-tighter mb-20">
            Let's <span className="text-white/40 italic">build</span> together.
          </h2>

          <div className="w-full pt-12 border-t border-white/5 flex flex-col md:flex-row justify-between items-center gap-8 text-white/30 text-xs font-bold tracking-widest uppercase">
            <div>© 2024 JT DESIGN STUDIO</div>
            <div className="flex gap-8">
              <a href="#" className="hover:text-white transition-colors">LinkedIn</a>
              <a href="#" className="hover:text-white transition-colors">Behance</a>
              <a href="#" className="hover:text-white transition-colors">Instagram</a>
            </div>
            <div>LOCATED IN BERLIN, DE</div>
          </div>
        </div>
      </footer>
    </div>
  );
};

