          100% { left: 110%; opacity: 0; }
        }
        .group-hover\/next-full\:animate-cinematic-scan {
          animation: cinematic-scan 4s cubic-bezier(0.16, 1, 0.3, 1) infinite;
        }
        @keyframes slide-right {
          0% { transform: translateX(-6px); opacity: 0.5; }
          50% { transform: translateX(6px); opacity: 1; }
          100% { transform: translateX(-6px); opacity: 0.5; }
        }
        .animate-slide-right {
          animation: slide-right 2.5s ease-in-out infinite;
        }
      `}</style>
    </div>
  );
};

const CaseStudiesView: React.FC<{ projects: Project[] }> = ({ projects }) => {
  const [activeIdx, setActiveIdx] = useState(0);

  const handleNext = useCallback(() => {
    setActiveIdx((prev) => (prev + 1) % projects.length);
  }, [projects.length]);

  const handlePrev = useCallback(() => {
    setActiveIdx((prev) => (prev - 1 + projects.length) % projects.length);
  }, [projects.length]);

  const activeProject = projects[activeIdx];

  return (
    <section className="min-h-screen pt-32 pb-20 px-6 md:px-12 bg-black flex flex-col items-center overflow-hidden">
      <div className="w-full max-w-[1400px]">
        <div className="mb-16 reveal">
          <h1 className="text-6xl md:text-[8rem] font-bold tracking-tighter leading-none mb-6">
            Deep <span className="text-white/20 italic">Dives</span>
          </h1>
        </div>

        <div 
          key={activeProject.id}
          className={`relative aspect-[16/10] md:aspect-[21/11] rounded-[3rem] overflow-hidden glass border border-white/10 shadow-[0_0_100px_rgba(255,255,255,0.02)] group animate-carousel-entry`}
        >
          <div className="absolute inset-0 z-0 bg-[#080808]">
            <img 
              src={activeProject.imageUrl} 
              alt={activeProject.title} 
              className={`w-full h-full object-cover transition-all duration-[2s] ease-out transform scale-110 animate-ken-burns`}
            />
            <div className="absolute inset-0 bg-gradient-to-t from-black via-black/20 to-black/10"></div>
          </div>

          <div className="absolute inset-0 z-10 p-12 md:p-20 flex flex-col justify-end items-start text-left">
            <h2 className="text-6xl md:text-[9rem] font-bold tracking-tighter leading-[0.8] mb-10">
              {activeProject.title}
            </h2>
          </div>

          <div className="absolute right-10 top-1/2 -translate-y-1/2 z-20 flex flex-col gap-6">
            <button 
              onClick={handlePrev}
              className="w-16 h-16 rounded-full border border-white/10 bg-black/50 backdrop-blur-xl flex items-center justify-center text-white/40 hover:text-white transition-all shadow-2xl"
            >
              <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16l-4-4m0 0l4-4m-4 4h18" />
              </svg>
            </button>
            <button 
              onClick={handleNext}
              className="w-16 h-16 rounded-full border border-white/10 bg-black/50 backdrop-blur-xl flex items-center justify-center text-white/40 hover:text-white transition-all shadow-2xl"
            >
              <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 8l4 4m0 0l-4 4m4-4H3" />
              </svg>
            </button>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes carousel-entry {
          0% { opacity: 0; transform: scale(0.98); }
          100% { opacity: 1; transform: scale(1); }
        }
        .animate-carousel-entry {
          animation: carousel-entry 1s cubic-bezier(0.16, 1, 0.3, 1) forwards;
        }
      `}</style>
    </section>
  );
};

const InfoView: React.FC = () => {
  return (
